def erode_matrix(matrix, iterations=1):
    """
    对二值矩阵进行腐蚀操作，让 1 的范围变小
    """
    import copy
    # 深拷贝，避免修改原数据
    mat = copy.deepcopy(matrix)
    rows = len(mat)
    cols = len(mat[0]) if rows > 0 else 0

    for _ in range(iterations):
        new_mat = [row[:] for row in mat]  # 浅拷贝行

        for i in range(1, rows - 1):
            for j in range(1, cols - 1):
                # 如果当前是 1
                if mat[i][j] == '1':
                    # 检查 4 邻域 (上下左右)
                    # 如果任何一个邻域是 '0'，则当前点在腐蚀后应该变为 '0'
                    if (mat[i - 1][j] == '0' or mat[i + 1][j] == '0' or
                            mat[i][j - 1] == '0' or mat[i][j + 1] == '0'):
                        new_mat[i][j] = '0'
        mat = new_mat

    return mat

